def create_json_file(slug, title, description, keywords, content):
    """Create a JSON file for a topic"""
    data = {
        "title": title,
        "description": description,
        "content": content,
        "seo_keywords": keywords,
        "slug": slug,
        "published_at": "2026-05-01",
        "author": "出版数字化研究院"
    }

    filepath = os.path.join(BASE_DIR, f"{slug}.json")
    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

    return filepath

